// ============================================================
// CREATOMATE TEMPLATE BUILDER v23.0 (STEPPED FLASH FIXED)
// ============================================================
// 
// FIX v23.0:
// - FIXED: Flash now uses SEQUENTIAL COMPOSITIONS on same track
// - Each composition has rgba opacity baked into fill_color
// - No animations needed - stepped opacity creates smooth fade-out
// - Compositions with empty elements[] act as solid color overlays
// - Zoom animation uses back-out easing for punch feel
//
// ============================================================

// ============================================================
// 🎛️ INPUT NODES - All data sources in one place
// ============================================================

const INPUT_NODES = {
  aiDirector: $('AI Video Director').first().json,
  conceptLoop: $('Loop Through Concepts').first().json,
  avatarUrl: $('Set Avatar URL').first().json,
  flashBroll: $('Aggregate Flash B-Roll').first().json,
  effectsLibrary: $('Creatomate Effects Library').first().json,
  shortsSource: $('Shorts Trigger').first().json?.source || {}
};

// ============================================================
// 🎛️ CONFIGURABLE SETTINGS
// ============================================================

// Video Output Settings
const VIDEO_SETTINGS = {
  outputFormat: 'mp4',
  width: 1080,
  height: 1920,
  frameRate: 30,
  previewWidth: 1080,
  previewHeight: 1920,
  usePreviewSize: true
};

// ============================================================
// 🚀 SCROLL-STOPPER INTRO SETTINGS (STEPPED COMPOSITION APPROACH)
// ============================================================
// 
// Psychology of short-form scroll-stopping:
// 1. INSTANT IMPACT: White flash at frame 0 triggers attention
// 2. MOTION PARALLAX: Zoom creates depth, signals "something happening"
// 3. TIMING: Must complete < 0.5s to not annoy, but long enough to register
// 4. CONTRAST: White on dark background = maximum visual punch
//
// TECHNICAL: Uses sequential compositions on same track with
// decreasing rgba opacity baked into fill_color. This creates
// a smooth stepped fade-out effect without needing animations.
//
// ============================================================

const INTRO_EFFECT = {
  enabled: true,

  // Stepped flash using sequential compositions
  // Each step is a composition with opacity in rgba fill_color
  flash: {
    enabled: true,
    baseTrack: 30,  // High track = renders on top
    steps: [
      // Step 1: FULL PUNCH - 100% white (quick hit)
      { time: 0,     duration: 0.017, opacity: 1.0 },
      // Step 2: 80% white
      { time: 0.017, duration: 0.017, opacity: 0.8 },
      // Step 3: 55% white
      { time: 0.034, duration: 0.017, opacity: 0.55 },
      // Step 4: 30% white
      { time: 0.051, duration: 0.025, opacity: 0.3 },
      // Step 5: 15% white
      { time: 0.076, duration: 0.035, opacity: 0.15 },
      // Step 6: 5% white (quick fade out)
      { time: 0.111, duration: 0.04,  opacity: 0.05 }
    ]
  },

  // Zoom settings - creates depth and "impact" feeling
  zoom: {
    enabled: true,
    startScale: "150%",       // Start zoomed in more for punch
    endScale: "100%",         // Settle to normal
    duration: 0.4,            // Quick but not jarring
    easing: "back-out"        // Overshoots slightly for punch feel
  }
};

// Screen Recording Glow Effect
const SCREEN_GLOW = {
  enabled: true,
  color: '#355A15',
  primaryOpacity: '60%',
  secondaryOpacity: '40%',
  primaryBlur: '25 vmin',
  secondaryBlur: '15 vmin'
};

// Caption Settings
const CAPTION_SETTINGS = {
  enabled: true,
  fontFamily: 'Montserrat',
  fontWeight: 900,
  fontSize: '9.5 vmin',
  fillColor: '#FFFFFF',
  strokeColor: '#000000',
  strokeWidth: '1.1 vmin',
  shadowColor: 'rgba(0,0,0,0.95)',
  shadowBlur: '1.3 vmin',
  maxLength: 14,
  effect: 'highlight',
  positionY: '68%'
};

// Background Settings
const BACKGROUND = {
  color: '#0a0a0a'
};

// Audio Settings
const AUDIO_SETTINGS = {
  baseUrl: 'https://pub-1710591b286a4bf3877267e2ce0828e1.r2.dev',
  defaultVolume: '7%',
  fadeIn: 0.5,
  fadeOut: 1.5
};

// ============================================================
// 📥 PARSE AI DIRECTOR OUTPUT
// ============================================================

let directorData;
const aiOutput = INPUT_NODES.aiDirector.output;

if (aiOutput && typeof aiOutput === 'object' && !Array.isArray(aiOutput)) {
  directorData = aiOutput;
} else if (Array.isArray(aiOutput)) {
  try {
    const messageBlock = aiOutput.find(o => o.type === 'message');
    if (messageBlock) {
      const textContent = messageBlock.content[0].text;
      directorData = typeof textContent === 'string' 
        ? JSON.parse(textContent) 
        : textContent;
    } else {
      const textContent = aiOutput[1]?.content?.[0]?.text;
      directorData = typeof textContent === 'string' 
        ? JSON.parse(textContent) 
        : textContent;
    }
  } catch (e) {
    console.error('Parse error:', e.message);
    directorData = {};
  }
} else {
  directorData = {};
}

// ============================================================
// 📊 DERIVED CONSTANTS
// ============================================================

const conceptData = INPUT_NODES.conceptLoop;
const avatarUrl = INPUT_NODES.avatarUrl.avatar_video_url;
const avatarDuration = INPUT_NODES.avatarUrl.avatar_duration || INPUT_NODES.avatarUrl.duration || null;
const flashBrollGenerated = INPUT_NODES.flashBroll.flash_broll_generated || [];
const lib = INPUT_NODES.effectsLibrary;
const sourceData = INPUT_NODES.shortsSource;

// Build AI B-roll URL lookup
const aiBrollUrls = {};
flashBrollGenerated.forEach(clip => {
  const index = (clip.flash_number || 1) - 1;
  aiBrollUrls[index] = clip.video_url;
});

// Storyboard and styling
const storyboard = directorData.enhanced_storyboard || directorData.storyboard || [];
const conceptType = directorData.concept_type || conceptData.concept_type || 'bold';
const accentColor = lib.accent_colors?.[conceptType] || lib.accent_colors?.[Object.keys(lib.accent_colors || {})[0]] || '#00E676';

// Final constants
const AVATAR_URL = avatarUrl;
const SCREEN_URL = sourceData.video_url || directorData.video_url;
const AI_BROLL_URLS = aiBrollUrls;
const STORYBOARD = storyboard;
const ACTUAL_AVATAR_DURATION = avatarDuration || directorData.total_duration_seconds || directorData.total_duration;
const ACCENT_COLOR = accentColor;

// Audio track selection
const audioTrackId = directorData.audio_track || Object.keys(lib.audio_tracks || {})[0] || 7;
const selectedTrack = lib.audio_tracks?.[audioTrackId];

// ============================================================
// 🔧 HELPER FUNCTIONS
// ============================================================

function getDefaultLayout() {
  const layoutKeys = Object.keys(lib.layouts || {});
  const withAvatar = layoutKeys.find(k => lib.layouts[k].avatar);
  const anyLayout = layoutKeys[0];

  if (withAvatar) return lib.layouts[withAvatar];
  if (anyLayout) return lib.layouts[anyLayout];

  return {
    id: "FALLBACK",
    avatar: { x: "50%", y: "50%", width: "100%", height: "100%" },
    screen: null,
    divider_y: null
  };
}

function getLayout(layoutId) {
  if (layoutId && lib.layouts?.[layoutId]) {
    return lib.layouts[layoutId];
  }
  return getDefaultLayout();
}

// ============================================================
// 🎬 TRANSITION SYSTEM (DYNAMIC FROM EFFECTS LIBRARY)
// ============================================================

const OVERLAY_TRANSITION_TYPES = [
  'flash', 'double_flash', 'rgb_glitch', 'accent_flash', 
  'glitch_bars', 'zoom_shake', 'whip_pan'
];

function isOverlayTransition(transitionId) {
  if (!transitionId) return false;
  const trans = lib.transitions?.[transitionId];
  if (!trans) return false;
  return OVERLAY_TRANSITION_TYPES.includes(trans.type);
}

// ============================================================
// 🚀 SCROLL-STOPPER INTRO BUILDERS (STEPPED COMPOSITION APPROACH)
// ============================================================

/**
 * Build intro flash overlay elements using STEPPED COMPOSITIONS.
 * 
 * KEY INSIGHT: Creatomate's fade animations don't support fade-OUT.
 * Instead, we use sequential compositions on the SAME TRACK with
 * decreasing rgba opacity baked into fill_color. This creates a
 * smooth stepped fade-out effect without needing any animations.
 * 
 * - All compositions on same track = they play SEQUENTIALLY
 * - Each has explicit time + duration for precise control
 * - Opacity is in rgba format: "rgba(255,255,255,0.75)"
 * - Empty elements[] array = solid color overlay
 * 
 * @returns {Array} Array of composition elements for the flash effect
 */
function buildIntroFlashElements() {
  if (!INTRO_EFFECT.enabled || !INTRO_EFFECT.flash.enabled) return [];

  const flashElements = [];
  const track = INTRO_EFFECT.flash.baseTrack;

  INTRO_EFFECT.flash.steps.forEach((step) => {
    flashElements.push({
      type: "composition",
      track: track,  // ALL on same track = sequential playback
      time: step.time,
      duration: step.duration,
      fill_color: `rgba(255,255,255,${step.opacity})`,  // Opacity baked in!
      width: "100%",
      height: "100%",
      elements: []  // Empty = solid color overlay
    });
  });

  return flashElements;
}

/**
 * Build intro zoom animation using PROPER Creatomate syntax.
 * 
 * Uses back-out easing for that "punch" feel where it slightly
 * overshoots then settles back. Combined with flash, creates
 * the scroll-stopping impact moment.
 * 
 * @returns {Object|null} Animation object for the animations array
 */
function buildIntroZoomAnimation() {
  if (!INTRO_EFFECT.enabled || !INTRO_EFFECT.zoom.enabled) return null;

  return {
    type: "scale",
    time: 0,  // Start immediately
    duration: INTRO_EFFECT.zoom.duration,
    easing: INTRO_EFFECT.zoom.easing,
    start_scale: INTRO_EFFECT.zoom.startScale,
    end_scale: INTRO_EFFECT.zoom.endScale,
    scope: "element",
    fade: false
  };
}

// ============================================================
// 🎬 OTHER TRANSITION/ANIMATION HELPERS
// ============================================================

function buildTransitionOverlays(time, transitionId) {
  const trans = lib.transitions?.[transitionId];
  if (!trans) return [];

  const elements = [];
  let trackOffset = 20;

  switch (trans.type) {
    case 'flash':
    case 'double_flash':
      // Use stepped composition approach for mid-video flashes too
      const flashSteps = [
        { timeOffset: 0,     duration: 0.03, opacity: 1.0 },
        { timeOffset: 0.03,  duration: 0.03, opacity: 0.7 },
        { timeOffset: 0.06,  duration: 0.04, opacity: 0.4 },
        { timeOffset: 0.10,  duration: 0.05, opacity: 0.15 }
      ];
      flashSteps.forEach((step, i) => {
        elements.push({
          type: "composition",
          track: trackOffset + i,
          time: time + step.timeOffset,
          duration: step.duration,
          fill_color: `rgba(255,255,255,${step.opacity})`,
          width: "100%",
          height: "100%",
          elements: []
        });
      });
      break;

    case 'rgb_glitch':
      // Build RGB color layers
      const rgbSteps = [
        { color: "255,0,0", opacity: 0.5, xOffset: "-2%" },
        { color: "0,255,0", opacity: 0.5, xOffset: "0%" },
        { color: "0,0,255", opacity: 0.5, xOffset: "2%" }
      ];
      rgbSteps.forEach((layer, i) => {
        elements.push({
          type: "composition",
          track: trackOffset + i,
          time: time,
          duration: trans.duration || 0.12,
          fill_color: `rgba(${layer.color},${layer.opacity})`,
          width: "100%",
          height: "100%",
          x: layer.xOffset,
          blend_mode: "screen",
          elements: []
        });
      });
      // Follow-up white flash
      const whiteFlashSteps = [
        { timeOffset: 0,    duration: 0.03, opacity: 1.0 },
        { timeOffset: 0.03, duration: 0.05, opacity: 0.5 },
        { timeOffset: 0.08, duration: 0.07, opacity: 0.15 }
      ];
      whiteFlashSteps.forEach((step, i) => {
        elements.push({
          type: "composition",
          track: trackOffset + rgbSteps.length + i,
          time: time + (trans.duration || 0.12) * 0.5 + step.timeOffset,
          duration: step.duration,
          fill_color: `rgba(255,255,255,${step.opacity})`,
          width: "100%",
          height: "100%",
          elements: []
        });
      });
      break;

    case 'accent_flash':
      // Accent color punch followed by white
      const accentSteps = [
        { timeOffset: 0,    duration: 0.04, opacity: 0.7, color: ACCENT_COLOR.replace('#', '') },
        { timeOffset: 0.04, duration: 0.04, opacity: 0.3, color: ACCENT_COLOR.replace('#', '') }
      ];
      // Convert hex to rgb for accent
      const hexToRgb = (hex) => {
        const r = parseInt(hex.substring(0, 2), 16);
        const g = parseInt(hex.substring(2, 4), 16);
        const b = parseInt(hex.substring(4, 6), 16);
        return `${r},${g},${b}`;
      };
      const accentRgb = hexToRgb(ACCENT_COLOR.replace('#', ''));
      accentSteps.forEach((step, i) => {
        elements.push({
          type: "composition",
          track: trackOffset + i,
          time: time + step.timeOffset,
          duration: step.duration,
          fill_color: `rgba(${accentRgb},${step.opacity})`,
          width: "100%",
          height: "100%",
          elements: []
        });
      });
      // White flash after accent
      const whiteAfterAccent = [
        { timeOffset: 0.05, duration: 0.03, opacity: 1.0 },
        { timeOffset: 0.08, duration: 0.04, opacity: 0.6 },
        { timeOffset: 0.12, duration: 0.08, opacity: 0.2 }
      ];
      whiteAfterAccent.forEach((step, i) => {
        elements.push({
          type: "composition",
          track: trackOffset + accentSteps.length + i,
          time: time + step.timeOffset,
          duration: step.duration,
          fill_color: `rgba(255,255,255,${step.opacity})`,
          width: "100%",
          height: "100%",
          elements: []
        });
      });
      break;

    case 'zoom_shake':
      // White flash with zoom feel
      const zoomFlashSteps = [
        { timeOffset: 0,    duration: 0.04, opacity: 1.0 },
        { timeOffset: 0.04, duration: 0.06, opacity: 0.6 },
        { timeOffset: 0.10, duration: 0.10, opacity: 0.25 },
        { timeOffset: 0.20, duration: 0.10, opacity: 0.08 }
      ];
      zoomFlashSteps.forEach((step, i) => {
        elements.push({
          type: "composition",
          track: trackOffset + i,
          time: time + step.timeOffset,
          duration: step.duration,
          fill_color: `rgba(255,255,255,${step.opacity})`,
          width: "100%",
          height: "100%",
          elements: []
        });
      });
      break;

    case 'whip_pan':
      // Horizontal wipe-style flash
      elements.push({
        type: "composition",
        track: trackOffset,
        time: time,
        duration: trans.duration || 0.15,
        fill_color: "rgba(255,255,255,1)",
        width: trans.width || "120%",
        height: "100%",
        y: "50%",
        x_anchor: "50%",
        y_anchor: "50%",
        elements: [],
        animations: [
          {
            type: "slide",
            time: 0,
            duration: trans.duration || 0.15,
            direction: "0°",
            distance: "120%",
            easing: "quadratic-out"
          }
        ]
      });
      break;

    default:
      // Generic flash fallback using stepped approach
      if (trans.color) {
        const genericSteps = [
          { timeOffset: 0,    duration: 0.03, opacity: 1.0 },
          { timeOffset: 0.03, duration: 0.05, opacity: 0.5 },
          { timeOffset: 0.08, duration: 0.07, opacity: 0.15 }
        ];
        genericSteps.forEach((step, i) => {
          elements.push({
            type: "composition",
            track: trackOffset + i,
            time: time + step.timeOffset,
            duration: step.duration,
            fill_color: `rgba(255,255,255,${step.opacity})`,
            width: "100%",
            height: "100%",
            elements: []
          });
        });
      }
  }

  return elements;
}

function buildTransitionAnimation(transitionId) {
  if (!transitionId) return null;

  const trans = lib.transitions?.[transitionId];
  if (!trans) return null;

  if (OVERLAY_TRANSITION_TYPES.includes(trans.type)) return null;
  if (trans.type === 'cut') return null;

  const animation = {
    time: 0,
    duration: trans.duration || 0.15,
    transition: true,
    easing: trans.easing || "quadratic-out"
  };

  switch (trans.type) {
    case 'scale':
      animation.type = "scale";
      animation.start_scale = trans.start_scale || "120%";
      break;

    case 'slide':
      animation.type = "slide";
      animation.direction = trans.direction || "0°";
      if (trans.distance) animation.distance = trans.distance;
      animation.fade = trans.fade !== undefined ? trans.fade : false;
      break;

    case 'wipe':
      animation.type = "wipe";
      animation.direction = trans.direction || "left";
      break;

    case 'fade':
      animation.type = "fade";
      break;

    default:
      return null;
  }

  return animation;
}

function getAvatarAnimation(animationId) {
  if (!animationId) return [];

  const anim = lib.avatar_animations?.[animationId];
  if (!anim || anim.type === 'none') return [];

  switch (anim.type) {
    case 'scale':
      return [{ 
        type: "scale", 
        time: 0, 
        duration: anim.duration || 0.2, 
        start_scale: anim.start_scale || "108%", 
        easing: anim.easing || "quadratic-out"
      }];

    case 'slide':
      return [{ 
        type: "slide", 
        time: 0, 
        duration: anim.duration || 0.25, 
        direction: anim.direction === 'up' ? "90°" : "270°",
        distance: anim.distance || "10%",
        easing: anim.easing || "back-out"
      }];

    case 'fade':
      return [{
        type: "fade",
        time: 0,
        duration: anim.duration || 0.3,
        start_opacity: anim.start_opacity || "0%"
      }];

    default:
      return [];
  }
}

function getScreenMotion(motionId, duration) {
  const defaultMotion = { 
    scale: [{ time: "0 s", value: "100%" }], 
    x: [{ time: "0 s", value: "50%" }], 
    y: [{ time: "0 s", value: "50%" }] 
  };

  if (!motionId) return defaultMotion;

  const motion = lib.screen_motions?.[motionId];
  if (!motion) return defaultMotion;

  if (motion.type === 'static') return defaultMotion;

  if (motion.type === 'zoom') {
    return {
      scale: [
        { time: "0 s", value: motion.start_scale || "100%", easing: motion.easing || "linear" },
        { time: `${duration} s`, value: motion.end_scale || "108%" }
      ],
      x: [{ time: "0 s", value: "50%" }],
      y: [{ time: "0 s", value: "50%" }]
    };
  }

  if (motion.type === 'pan') {
    return {
      scale: [{ time: "0 s", value: "100%" }],
      x: [
        { time: "0 s", value: motion.start_x || "50%", easing: motion.easing || "linear" },
        { time: `${duration} s`, value: motion.end_x || "50%" }
      ],
      y: [
        { time: "0 s", value: motion.start_y || "50%", easing: motion.easing || "linear" },
        { time: `${duration} s`, value: motion.end_y || "50%" }
      ]
    };
  }

  return defaultMotion;
}

function buildTextOverlay(styleId, content, time, duration) {
  if (!styleId || !content) return null;

  const style = lib.text_styles?.[styleId];
  if (!style) return null;

  const fillColor = (style.fill_color || "#FFFFFF").replace("{{ACCENT_COLOR}}", ACCENT_COLOR);
  const bgColor = style.background_color?.replace("{{ACCENT_COLOR}}", ACCENT_COLOR);

  const textElement = {
    type: "text",
    track: 10,
    time: time + 0.2,
    duration: duration - 0.3,
    text: content,
    x: style.position?.x || "50%",
    y: style.position?.y || "78%",
    width: "92%",
    x_anchor: "50%",
    y_anchor: "50%",
    x_alignment: "50%",
    font_family: style.font_family,
    font_weight: style.font_weight,
    font_size: style.font_size,
    fill_color: fillColor,
    animations: [
      { type: "scale", time: 0, duration: 0.25, easing: "back-out", start_scale: "90%" },
      { type: "fade", time: "end", duration: 0.15 }
    ]
  };

  if (style.stroke_color) textElement.stroke_color = style.stroke_color;
  if (style.stroke_width) textElement.stroke_width = style.stroke_width;
  if (style.shadow_color) textElement.shadow_color = style.shadow_color;
  if (style.shadow_blur) textElement.shadow_blur = style.shadow_blur;
  if (bgColor) textElement.background_color = bgColor;
  if (style.background_x_padding) textElement.background_x_padding = style.background_x_padding;
  if (style.background_y_padding) textElement.background_y_padding = style.background_y_padding;
  if (style.background_border_radius) textElement.background_border_radius = style.background_border_radius;

  return textElement;
}

function getBrollVideoUrl(beat) {
  if (beat.broll_type === 'screen') return SCREEN_URL;
  if (beat.broll_type === 'ai_generated' && beat.ai_broll_index != null && beat.ai_broll_index >= 0) {
    return AI_BROLL_URLS[beat.ai_broll_index] || null;
  }
  return null;
}

function getBrollTrimSettings(beat, duration) {
  if (beat.broll_type === 'screen') {
    const startTime = beat.broll_start_seconds || 0;
    const aiSpecifiedDuration = beat.broll_end_seconds && beat.broll_start_seconds 
      ? beat.broll_end_seconds - beat.broll_start_seconds 
      : null;

    return {
      trim_start: startTime,
      trim_duration: duration + 0.5,
      _ai_specified_duration: aiSpecifiedDuration,
      _was_corrected: aiSpecifiedDuration !== null && aiSpecifiedDuration < duration
    };
  }

  if (beat.broll_type === 'ai_generated') {
    return { 
      trim_start: 0, 
      trim_duration: duration + 0.5
    };
  }

  return null;
}

// ============================================================
// 🏗️ BUILD ELEMENTS ARRAY
// ============================================================

const elements = [];
let avatarTrimPosition = 0;
let overlayTransitionCount = 0;
let brollDurationCorrections = [];
let introFlashCount = 0;
let introZoomApplied = false;

// Track 1: Background Music
if (selectedTrack) {
  elements.push({
    type: "audio",
    track: 1,
    source: `${AUDIO_SETTINGS.baseUrl}/${selectedTrack.file || selectedTrack.name.toLowerCase().replace(/ /g, '_') + '.mp3'}`,
    volume: selectedTrack.volume || AUDIO_SETTINGS.defaultVolume,
    loop: true,
    audio_fade_in: AUDIO_SETTINGS.fadeIn,
    audio_fade_out: AUDIO_SETTINGS.fadeOut
  });
}

// Track 2: Master Avatar (hidden, for audio & caption sync)
elements.push({
  id: "avatar-master",
  type: "video",
  track: 2,
  time: 0,
  source: AVATAR_URL,
  volume: "100%",
  y: "200%",
  fit: "cover"
});

// Track 3: Black Background
elements.push({
  type: "shape",
  track: 3,
  time: 0,
  duration: ACTUAL_AVATAR_DURATION + 5,
  shape: "rectangle",
  width: "100%",
  height: "100%",
  fill_color: BACKGROUND.color
});

// ============================================================
// 🚀 ADD INTRO FLASH ELEMENTS (Track 30 - stepped compositions)
// ============================================================
const introFlashElements = buildIntroFlashElements();
introFlashElements.forEach(el => {
  elements.push(el);
  introFlashCount++;
});

// ============================================================
// 🎬 PROCESS EACH STORYBOARD BEAT
// ============================================================

let currentTime = 0;

STORYBOARD.forEach((beat, idx) => {
  const duration = beat.duration_seconds || 4;
  const layout = getLayout(beat.layout);
  const screenMotion = getScreenMotion(beat.screen_motion, duration);
  const avatarAnimations = getAvatarAnimation(beat.avatar_animation);

  const isIntroBeat = idx === 0;

  // Handle transitions (not for first beat)
  let transitionAnimation = null;
  if (!isIntroBeat && beat.transition_in) {
    if (isOverlayTransition(beat.transition_in)) {
      const overlayElements = buildTransitionOverlays(currentTime, beat.transition_in);
      overlayElements.forEach(el => elements.push(el));
      overlayTransitionCount++;
    } else {
      transitionAnimation = buildTransitionAnimation(beat.transition_in);
    }
  }

  // ============================================================
  // AVATAR ELEMENT
  // ============================================================
  if (layout.avatar) {
    const avatarElement = {
      type: "video",
      track: 4,
      time: currentTime,
      duration: duration,
      source: AVATAR_URL,
      trim_start: avatarTrimPosition,
      trim_duration: duration,
      volume: 0,
      x: layout.avatar.x,
      y: layout.avatar.y,
      width: layout.avatar.width,
      height: layout.avatar.height,
      x_anchor: "50%",
      y_anchor: "50%",
      fit: "cover",
      clip: true
    };

    if (layout.avatar.border_radius) {
      avatarElement.border_radius = layout.avatar.border_radius;
    }

    // Build animations array
    const allAnimations = [];

    // INTRO: First beat gets scroll-stopper zoom
    if (isIntroBeat && INTRO_EFFECT.enabled && INTRO_EFFECT.zoom.enabled) {
      const introZoom = buildIntroZoomAnimation();
      if (introZoom) {
        allAnimations.push(introZoom);
        introZoomApplied = true;
      }
    } else {
      if (transitionAnimation) allAnimations.push(transitionAnimation);
      avatarAnimations.forEach(a => allAnimations.push(a));
    }

    if (allAnimations.length > 0) {
      avatarElement.animations = allAnimations;
    }

    elements.push(avatarElement);
  }

  // ============================================================
  // B-ROLL ELEMENT
  // ============================================================
  const brollUrl = getBrollVideoUrl(beat);
  const brollTrim = getBrollTrimSettings(beat, duration);

  if (brollTrim && brollTrim._was_corrected) {
    brollDurationCorrections.push({
      beat_index: idx,
      beat_type: beat.beat_type,
      beat_duration: duration,
      ai_specified_duration: brollTrim._ai_specified_duration,
      correction_applied: true
    });
  }

  if (layout.screen && brollUrl && brollTrim) {

    const isScreenRecording = beat.broll_type === 'screen' || layout.is_padded_screen === true;
    const fitMode = isScreenRecording ? 'contain' : 'cover';

    const videoWidth = isScreenRecording ? '92%' : '120%';
    const videoHeight = isScreenRecording ? '88%' : '130%';

    const innerElements = [];

    if (isScreenRecording && SCREEN_GLOW.enabled) {
      innerElements.push({
        type: "shape",
        track: 1,
        shape: "rectangle",
        width: "100%",
        height: "100%",
        fill_color: "#0d0d0d"
      });

      innerElements.push({
        type: "shape",
        track: 2,
        shape: "rectangle",
        width: "70%",
        height: "60%",
        x: "50%",
        y: "50%",
        x_anchor: "50%",
        y_anchor: "50%",
        fill_color: SCREEN_GLOW.color,
        opacity: SCREEN_GLOW.primaryOpacity,
        shadow_color: SCREEN_GLOW.color,
        shadow_blur: SCREEN_GLOW.primaryBlur,
        border_radius: "5 vmin"
      });

      innerElements.push({
        type: "shape",
        track: 3,
        shape: "rectangle",
        width: "50%",
        height: "40%",
        x: "50%",
        y: "50%",
        x_anchor: "50%",
        y_anchor: "50%",
        fill_color: SCREEN_GLOW.color,
        opacity: SCREEN_GLOW.secondaryOpacity,
        shadow_color: SCREEN_GLOW.color,
        shadow_blur: SCREEN_GLOW.secondaryBlur,
        border_radius: "3 vmin"
      });

      innerElements.push({
        type: "shape",
        track: 4,
        shape: "rectangle",
        width: "93%",
        height: "89%",
        x: "50%",
        y: "50%",
        x_anchor: "50%",
        y_anchor: "50%",
        fill_color: "#0a0a0a",
        border_radius: "1.2 vmin",
        shadow_color: "rgba(0,0,0,0.8)",
        shadow_blur: "2 vmin"
      });
    }

    innerElements.push({
      type: "video",
      track: 5,
      source: brollUrl,
      volume: 0,
      trim_start: brollTrim.trim_start,
      trim_duration: brollTrim.trim_duration,
      x: "50%",
      y: "50%",
      x_anchor: "50%",
      y_anchor: "50%",
      width: videoWidth,
      height: videoHeight,
      fit: fitMode,
      border_radius: isScreenRecording ? "1 vmin" : "0",
      ...screenMotion
    });

    if (isScreenRecording && SCREEN_GLOW.enabled) {
      innerElements.push({
        type: "shape",
        track: 6,
        shape: "rectangle",
        width: "92%",
        height: "88%",
        x: "50%",
        y: "50%",
        x_anchor: "50%",
        y_anchor: "50%",
        fill_color: "rgba(0,0,0,0)",
        border_color: "rgba(255,255,255,0.1)",
        border_width: "0.3 vmin",
        border_radius: "1 vmin"
      });
    }

    const compositionElement = {
      type: "composition",
      track: 5,
      time: currentTime,
      duration: duration,
      x: layout.screen.x,
      y: layout.screen.y,
      width: layout.screen.width,
      height: layout.screen.height,
      x_anchor: "50%",
      y_anchor: "50%",
      clip: true,
      elements: innerElements
    };

    // INTRO: First beat gets scroll-stopper zoom on screen too
    if (isIntroBeat && INTRO_EFFECT.enabled && INTRO_EFFECT.zoom.enabled) {
      const introZoom = buildIntroZoomAnimation();
      if (introZoom) compositionElement.animations = [introZoom];
    } else if (!layout.avatar && transitionAnimation) {
      compositionElement.animations = [transitionAnimation];
    }

    elements.push(compositionElement);
  }

  // ============================================================
  // DIVIDER LINE
  // ============================================================
  if (layout.divider_y) {
    elements.push({
      type: "shape",
      track: 6,
      time: currentTime,
      duration: duration,
      shape: "rectangle",
      x: "50%",
      y: layout.divider_y,
      width: "100%",
      height: "0.5%",
      x_anchor: "50%",
      y_anchor: "50%",
      fill_color: ACCENT_COLOR,
      shadow_color: "rgba(0,0,0,0.5)",
      shadow_blur: "0.5 vmin"
    });
  }

  // ============================================================
  // TEXT OVERLAY
  // ============================================================
  if (beat.text_overlay && beat.text_content) {
    const textElement = buildTextOverlay(beat.text_overlay, beat.text_content, currentTime, duration);
    if (textElement) elements.push(textElement);
  }

  currentTime += duration;
  avatarTrimPosition += duration;
});

