// ============================================================================
// CHANGE: Now includes key_moments (4-8 second B-roll clips) from Gemini
// WHY: AI scriptwriter needs to know what's visually happening on screen
// to pick timestamps with maximum movement and write accurate descriptions
// ============================================================================

const input = $('Shorts Trigger').first().json;

// Get the pre-analyzed data from parent workflow
const source = input.source || {};
const overview = input.overview || {};
const transcript = input.transcript || {};
const links = input.links || {};

// NEW: B-roll clips from Gemini visual analysis (4-8 second moments)
const brollClips = input.key_moments || [];
const visualAnalysis = input.visual_analysis || {};

// Sections now include nested segments[] with sentence-level timestamps
const sections = transcript.sections || [];
const segments = transcript.segments || [];
const bestSectionsForShorts = transcript.best_sections_for_shorts || [];

// Convert sections to key_moments format (for downstream compatibility)
const keyMoments = sections
  .filter(section => section.hook_potential && section.hook_potential !== 'low')
  .map(section => ({
    section_index: section.index,
    timestamp_start: section.start,
    timestamp_end: section.end,
    start_formatted: section.start_formatted,
    end_formatted: section.end_formatted,
    duration_seconds: section.duration_seconds,
    description: section.summary,
    hook_potential: mapHookPotential(section.hook_potential),
    quote: section.quotable_moment || null,
    tools_shown: section.key_topics || [],
    section_title: section.title,
    section_type: section.section_type,
    segment_count: section.segment_count || (section.segments ? section.segments.length : 0)
  }));

// Map hook_potential to our concept types
function mapHookPotential(potential) {
  if (potential === 'high') return 'bold';
  if (potential === 'medium') return 'curiosity';
  return 'pain';
}

// Use best_sections_for_shorts as best_clips (already identified by AI!)
const bestClips = bestSectionsForShorts.map(sectionIndex => {
  const section = sections[sectionIndex];
  if (!section) return null;
  return {
    section_index: sectionIndex,
    start: section.start,
    end: section.end,
    start_formatted: section.start_formatted,
    end_formatted: section.end_formatted,
    duration_seconds: section.duration_seconds,
    description: section.summary,
    hook_potential: section.hook_potential,
    segment_count: section.segment_count || (section.segments ? section.segments.length : 0)
  };
}).filter(Boolean);

// If no best_sections identified, pick top 3 high-potential sections
if (bestClips.length === 0) {
  const highPotential = sections
    .filter(s => s.hook_potential === 'high' || s.hook_potential === 'medium')
    .slice(0, 3);

  highPotential.forEach(section => {
    bestClips.push({
      section_index: section.index,
      start: section.start,
      end: section.end,
      start_formatted: section.start_formatted,
      end_formatted: section.end_formatted,
      duration_seconds: section.duration_seconds,
      description: section.summary,
      hook_potential: section.hook_potential,
      segment_count: section.segment_count || (section.segments ? section.segments.length : 0)
    });
  });
}

// ============================================================================
// ENRICH B-ROLL CLIPS WITH SECTION CONTEXT
// ============================================================================
// Match each B-roll clip to its corresponding section for context
// ============================================================================

const enrichedBrollClips = brollClips.map((clip, index) => {
  // Find which section this clip falls into
  const matchingSection = sections.find(s => 
    clip.start_seconds >= s.start && clip.start_seconds < s.end
  );

  return {
    index: index,
    start: clip.start,
    end: clip.end,
    start_seconds: clip.start_seconds,
    end_seconds: clip.end_seconds,
    duration_seconds: (clip.end_seconds || 0) - (clip.start_seconds || 0),
    app: clip.app,
    action: clip.action,
    screen_description: clip.screen_description || null,
    // Section context
    section_index: matchingSection ? matchingSection.index : null,
    section_title: matchingSection ? matchingSection.title : null
  };
});

