// Image URLs
const AI_BUILDERS_HUB_LOGO = 'https://pub-83b11023a37e4e0cba93118736bb2799.r2.dev/AI%20Builders%20Hub%20Logo%20-%20Cropped.png';
const APG_SOFTWARE_LOGO = 'https://pub-66c549f8c8d44c16ab441b6668d7a12a.r2.dev/APG%20SOFTWARE%20(1).png';
const ADAM_PROFILE_PHOTO = 'https://pub-66c549f8c8d44c16ab441b6668d7a12a.r2.dev/Adam%20Goodyer.png';

// ============================================
// GET INPUT DATA
// ============================================
const markdownContent = $input.first().json.output || '';
const titleMatch = markdownContent.match(/^#\s+(.+)$/m);
const documentTitle = titleMatch ? titleMatch[1].trim() : 'Document';

function convertMarkdownToHtml(markdown) {
  let html = markdown;

  html = html.replace(/^#\s+.+$/m, '');

  html = html.replace(/```([\s\S]*?)```/g, (match, code) => {
    const escapedCode = code.trim().replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
    return `<pre>${escapedCode}</pre>`;
  });

  html = html.replace(/^>\s*⚡\s*\*\*Quick Win[^*]*\*\*:?\s*(.+)$/gm, (m, c) => 
    `<p><strong>⚡ Quick Win:</strong> ${c.trim()}</p>`);
  html = html.replace(/^>\s*💡\s*\*\*Pro Tip:?\*\*:?\s*(.+)$/gm, (m, c) => 
    `<p><strong>💡 Pro Tip:</strong> ${c.trim()}</p>`);
  html = html.replace(/^>\s*⚠️\s*\*\*Watch Out:?\*\*:?\s*(.+)$/gm, (m, c) => 
    `<p><strong>⚠️ Watch Out:</strong> ${c.trim()}</p>`);
  html = html.replace(/^>\s*ℹ️\s*\*\*Note:?\*\*:?\s*(.+)$/gm, (m, c) => 
    `<p><strong>ℹ️ Note:</strong> ${c.trim()}</p>`);

  html = html.replace(/^### (.+)$/gm, '<h3>$1</h3>');
  html = html.replace(/^## (.+)$/gm, '<h2>$1</h2>');

  html = html.replace(/^(\d+)\.\s+(.+)$/gm, '<li>$2</li>');
  html = html.replace(/((?:<li>.*<\/li>\n?)+)/g, (match) => {
    if (match.includes('<ul>') || match.includes('<ol>')) return match;
    return `<ol>\n${match}</ol>\n`;
  });

  html = html.replace(/^[-*]\s+(.+)$/gm, '<uli>$1</uli>');
  html = html.replace(/((?:<uli>.*<\/uli>\n?)+)/g, (match) => {
    return `<ul>\n${match.replace(/<\/?uli>/g, (t) => t.replace('uli', 'li'))}</ul>\n`;
  });

  html = html.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
  html = html.replace(/\*([^*]+)\*/g, '<em>$1</em>');
  html = html.replace(/`([^`]+)`/g, '<code>$1</code>');
  html = html.replace(/^---$/gm, '<hr>');

  const blocks = html.split(/\n\n+/);
  html = blocks.map(b => {
    b = b.trim();
    if (!b) return '';
    if (b.startsWith('<')) return b;
    return `<p>${b}</p>`;
  }).join('\n');

  return html;
}

const htmlContent = convertMarkdownToHtml(markdownContent);

const fullHtml = `<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <title>${documentTitle}</title>
</head>
<body>
  <h1 style="text-align:center;">Adam Goodyer</h1>
  <p style="text-align:center;">
    <img src="${ADAM_PROFILE_PHOTO}" width="120" height="120">
  </p>
  <p style="text-align:center;">
    <img src="${AI_BUILDERS_HUB_LOGO}" width="150" height="60">
    <img src="${APG_SOFTWARE_LOGO}" width="150" height="60">
  </p>
  <p style="text-align:center;">
    <a href="https://www.adamgoodyer.com">www.adamgoodyer.com</a>
  </p>
  <hr>
  <h1>${documentTitle}</h1>
  ${htmlContent}
  <hr>
  <p>Adam Goodyer | <a href="https://www.adamgoodyer.com">www.adamgoodyer.com</a></p>
</body>
</html>`;

// ============================================
// BUILD MULTIPART REQUEST
// ============================================
const boundary = 'docboundary';

const metadata = JSON.stringify({
  name: documentTitle,
  mimeType: "application/vnd.google-apps.document",
  parents: [FOLDER_ID]
});

let body = `--${boundary}\r\n`;
body += `Content-Type: application/json; charset=UTF-8\r\n`;
body += `\r\n`;
body += `${metadata}\r\n`;
body += `--${boundary}\r\n`;
body += `Content-Type: text/html\r\n`;
body += `\r\n`;
body += `${fullHtml}\r\n`;
body += `--${boundary}--\r\n`;

return {
  json: {
    document_name: documentTitle,
    rawData: body
  }
};

