{
  "type": "object",
  "properties": {
    "concept_index": {
      "type": "number",
      "description": "Index of the concept"
    },
    "concept_type": {
      "type": "string",
      "enum": ["pain", "curiosity", "transformation"],
      "description": "Type of concept hook"
    },
    "title": {
      "type": "string",
      "description": "Title of the video"
    },
    "audio_track": {
      "type": "number",
      "description": "Track number from the effects library audio_tracks section"
    },
    "total_duration_seconds": {
      "type": "number",
      "description": "Total video duration in seconds - must match avatar_duration exactly"
    },
    "total_beats": {
      "type": "number",
      "description": "Total number of beats. Target: 8-10 for 30s, 12-15 for 45s, 15-20 for 60s"
    },
    "total_flashes": {
      "type": "number",
      "description": "Number of flash-type transitions used. Check effects library guidelines for target."
    },
    "enhanced_storyboard": {
      "type": "array",
      "description": "Array of storyboard beats",
      "items": {
        "type": "object",
        "properties": {
          "beat_index": {
            "type": "number",
            "description": "Index of this beat starting from 0"
          },
          "beat_type": {
            "type": "string",
            "enum": ["hook_snap", "hook_reveal", "body_flash", "body_demo", "body_emphasis", "cta_close"],
            "description": "Type of beat"
          },
          "duration_seconds": {
            "type": "number",
            "description": "STRICT: 2-4 seconds per beat. NEVER exceed 4 seconds. Must match AI B-roll duration if used."
          },
          "narration": {
            "type": "string",
            "description": "Narration text for this beat"
          },
          "layout": {
            "type": "string",
            "description": "Layout ID from the effects library layouts section. First/last beats use avatar-only layouts. Middle beats use split or fullscreen layouts."
          },
          "transition_in": {
            "type": "string",
            "description": "Transition ID from effects library transitions section. Empty string for first beat. Fade-type only for CTA. Never repeat consecutively."
          },
          "screen_motion": {
            "type": "string",
            "description": "Screen motion ID from effects library screen_motions section. Required for split/fullscreen layouts with B-roll. Empty string for avatar-only beats."
          },
          "avatar_animation": {
            "type": "string",
            "description": "Avatar animation ID from effects library avatar_animations section. Empty string if none."
          },
          "text_overlay": {
            "type": "string",
            "description": "Always empty string - captions handle all text"
          },
          "text_content": {
            "type": "string",
            "description": "Always empty string - captions handle all text"
          },
          "energy": {
            "type": "string",
            "enum": ["high", "medium", "low"],
            "description": "Energy level of this beat"
          },
          "snap_word": {
            "type": "string",
            "description": "Attention phrase for flash-type transitions. Empty string if transition is not a flash type."
          },
          "broll_type": {
            "type": "string",
            "enum": ["none", "screen", "ai_generated"],
            "description": "Type of B-roll. CRITICAL: 'none' only valid for avatar-only layouts (last beat). Split and fullscreen layouts MUST use 'screen' or 'ai_generated'. Using 'none' with split/fullscreen layouts causes black screen errors."
          },
          "broll_index": {
            "type": "number",
            "description": "Index of screen share B-roll clip. Use -1 if broll_type is not 'screen'."
          },
          "broll_start_seconds": {
            "type": "number",
            "description": "Start timestamp within screen share clip. Use -1 if broll_type is not 'screen'."
          },
          "broll_end_seconds": {
            "type": "number",
            "description": "End timestamp within screen share clip. Use -1 if broll_type is not 'screen'."
          },
          "ai_broll_index": {
            "type": "number",
            "description": "Index of AI-generated B-roll clip (0, 1, or 2). Use -1 if broll_type is not 'ai_generated'. CRITICAL: When not -1, duration_seconds MUST exactly match the AI B-roll clip duration."
          },
          "visual_description": {
            "type": "string",
            "description": "Description of the visual for this beat"
          }
        },
        "required": [
          "beat_index",
          "beat_type",
          "duration_seconds",
          "narration",
          "layout",
          "transition_in",
          "screen_motion",
          "avatar_animation",
          "text_overlay",
          "text_content",
          "energy",
          "snap_word",
          "broll_type",
          "broll_index",
          "broll_start_seconds",
          "broll_end_seconds",
          "ai_broll_index",
          "visual_description"
        ]
      }
    }
  },
  "required": [
    "concept_index",
    "concept_type",
    "title",
    "audio_track",
    "total_duration_seconds",
    "total_beats",
    "total_flashes",
    "enhanced_storyboard"
  ]
}

